"use client"

import { useEffect, useState } from "react"
import { supabase } from "@/lib/supabase"
import { getFactoryId } from "@/lib/factory"
import { formatCurrency } from "@/lib/format"
import { Wallet, ShoppingCart, Factory, BarChart3 } from "lucide-react"

export function Dashboard({
  setActiveTab,
}: {
  setActiveTab: (tab: string) => void
}) {
  const [sales, setSales] = useState<any[]>([])
  const [expenses, setExpenses] = useState<any[]>([])
  const [production, setProduction] = useState<any[]>([])
  const [loans, setLoans] = useState<any[]>([])
  const [bank, setBank] = useState<any[]>([])
  const [debts, setDebts] = useState<any[]>([])
  const [factoryName, setFactoryName] = useState("")

  useEffect(() => {
    const loadData = async () => {
      const factoryId = getFactoryId()
      if (!factoryId) return

      const [{ data: salesData }, { data: expenseData }, { data: productionData }, { data: loanData }, { data: bankData }, { data: debtData }] =
        await Promise.all([
          supabase.from("sales").select("*").eq("factory_id", factoryId).order("date", { ascending: false }),
          supabase.from("expenses").select("*").eq("factory_id", factoryId).order("date", { ascending: false }),
          supabase.from("production").select("*").eq("factory_id", factoryId).order("date", { ascending: false }),
          supabase.from("loans").select("*").eq("factory_id", factoryId).order("created_at", { ascending: false }),
          supabase.from("bank").select("*").eq("factory_id", factoryId).order("created_at", { ascending: false }),
          supabase.from("debts").select("*").eq("factory_id", factoryId).order("created_at", { ascending: false }),
        ])

      setSales(salesData || [])
      setExpenses(expenseData || [])
      setProduction(productionData || [])
      setLoans(loanData || [])
      setBank(bankData || [])
      setDebts(debtData || [])

      const name = localStorage.getItem("factoryName")
      if (name) setFactoryName(name)
    }

    loadData()
  }, [])

  const totalSales = sales.reduce((s, i) => s + Number(i.total_amount || 0), 0)
  const totalExpenses = expenses.reduce((s, i) => s + Number(i.amount || 0), 0)
  const totalProduction = production.reduce((s, i) => s + Number(i.bags_produced || 0), 0)

  const totalDebts = debts.reduce((s, d) => s + Number(d.amount || 0), 0)

  const deposits = bank
    .filter((t) => t.type === "deposit")
    .reduce((s, t) => s + Number(t.amount || 0), 0)

  const withdrawals = bank
    .filter((t) => t.type === "withdraw")
    .reduce((s, t) => s + Number(t.amount || 0), 0)

  const bankBalance = deposits - withdrawals

  const totalLoans = loans.reduce((s, l) => s + Number(l.amount || 0), 0)
  const totalLoanPaid = loans.reduce((s, l) => s + Number(l.amount_paid || 0), 0)
  const outstandingLoans = totalLoans - totalLoanPaid

  const cashOnHand = totalSales - totalExpenses - deposits
  const netPosition = cashOnHand + bankBalance + totalDebts - outstandingLoans

  const recentActivity = [
    ...sales.map((s) => ({
      type: "sale",
      label: s.customer_name ? `Sale to ${s.customer_name}` : "Sale",
      amount: Number(s.total_amount || 0),
      date: s.date || s.created_at || "",
    })),
    ...expenses.map((e) => ({
      type: "expense",
      label: e.category || e.notes || "Expense",
      amount: Number(e.amount || 0),
      date: e.date || e.created_at || "",
    })),
    ...production.map((p) => ({
      type: "production",
      label: `${Number(p.bags_produced || 0)} bags produced`,
      amount: Number(p.bags_produced || 0),
      date: p.date || p.created_at || "",
    })),
  ]
    .sort((a, b) => (b.date || "").localeCompare(a.date || ""))
    .slice(0, 6)

  return (
    <div className="space-y-4 pb-24">
      <div className="bg-[#0d1b3e] text-white rounded-2xl p-5 shadow-md">
        <p className="text-xs opacity-80">
          {factoryName || "Factory"} Financial Overview
        </p>

        <p className="text-2xl font-bold mt-2">
          {formatCurrency(cashOnHand)}
        </p>

        <p className="text-xs opacity-70">Cash on Hand</p>

        <div className="grid grid-cols-2 gap-4 mt-5 text-sm">
          <div>
            <p className="opacity-70">Bank</p>
            <p className="font-semibold">{formatCurrency(bankBalance)}</p>
          </div>

          <div>
            <p className="opacity-70">Loans</p>
            <p className="font-semibold">{formatCurrency(outstandingLoans)}</p>
          </div>

          <div>
            <p className="opacity-70">Debts</p>
            <p className="font-semibold">{formatCurrency(totalDebts)}</p>
          </div>

          <div>
            <p className="opacity-70">Net Position</p>
            <p className="font-semibold">{formatCurrency(netPosition)}</p>
          </div>
        </div>
      </div>

      <div>
        <p className="text-sm font-semibold text-gray-700 mb-2">Quick Actions</p>

        <div className="grid grid-cols-2 gap-3">
          <button
            onClick={() => setActiveTab("expenses")}
            className="flex items-center gap-3 bg-[#2563eb] text-white py-3 px-3 rounded-xl font-medium shadow-sm transition active:scale-[0.97]"
          >
            <div className="bg-white/20 p-1.5 rounded-lg">
              <Wallet size={16} />
            </div>
            Add Expense
          </button>

          <button
            onClick={() => setActiveTab("sales")}
            className="flex items-center gap-3 bg-blue-50 text-[#1f3a8a] py-3 px-3 rounded-xl font-medium transition active:scale-[0.97]"
          >
            <div className="bg-blue-100 p-1.5 rounded-lg">
              <ShoppingCart size={16} />
            </div>
            Add Sale
          </button>

          <button
            onClick={() => setActiveTab("production")}
            className="flex items-center gap-3 bg-blue-50 text-[#1f3a8a] py-3 px-3 rounded-xl font-medium transition active:scale-[0.97]"
          >
            <div className="bg-blue-100 p-1.5 rounded-lg">
              <Factory size={16} />
            </div>
            Production
          </button>

          <button
            onClick={() => setActiveTab("reports")}
            className="flex items-center gap-3 bg-orange-50 text-[#1f3a8a] py-3 px-3 rounded-xl font-medium transition active:scale-[0.97]"
          >
            <div className="bg-orange-100 p-1.5 rounded-lg">
              <BarChart3 size={16} />
            </div>
            Reports
          </button>
        </div>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm">
        <p className="text-sm font-semibold text-gray-700 mb-2">Summary</p>

        <div className="space-y-2 text-sm">
          <div className="flex justify-between">
            <span>Sales</span>
            <span>{formatCurrency(totalSales)}</span>
          </div>

          <div className="flex justify-between">
            <span>Expenses</span>
            <span>{formatCurrency(totalExpenses)}</span>
          </div>

          <div className="flex justify-between">
            <span>Production</span>
            <span>{totalProduction} bags</span>
          </div>
        </div>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm">
        <p className="text-sm font-semibold text-gray-700 mb-3">Recent Activity</p>

        {recentActivity.length === 0 ? (
          <p className="text-sm text-gray-500">No recent activity yet</p>
        ) : (
          recentActivity.map((item, index) => {
            const isSale = item.type === "sale"
            const isExpense = item.type === "expense"
            const isProduction = item.type === "production"

            return (
              <div
                key={index}
                className="flex items-center justify-between py-2 border-b last:border-none"
              >
                <div className="flex items-center gap-2">
                  <div
                    className={`p-1.5 rounded-lg ${
                      isSale
                        ? "bg-green-100 text-green-600"
                        : isExpense
                        ? "bg-red-100 text-red-500"
                        : "bg-blue-100 text-[#0d1b3e]"
                    }`}
                  >
                    {isSale && <span>📈</span>}
                    {isExpense && <span>📉</span>}
                    {isProduction && <span>📦</span>}
                  </div>

                  <div>
                    <p className="text-sm font-medium text-gray-800">
                      {item.label}
                    </p>
                    <p className="text-xs text-gray-400">
                      {item.date || "No date"}
                    </p>
                  </div>
                </div>

                <p
                  className={`text-sm font-semibold ${
                    isSale
                      ? "text-green-600"
                      : isExpense
                      ? "text-red-500"
                      : "text-[#0d1b3e]"
                  }`}
                >
                  {isProduction
                    ? `${item.amount} bags`
                    : `${isExpense ? "-" : "+"}${formatCurrency(item.amount)}`}
                </p>
              </div>
            )
          })
        )}
      </div>
    </div>
  )
}